import React, { useState } from "react";
import { ChevronLeft, Target } from "lucide-react";
import { useCurrency } from "../context/CurrencyContext";

export default function SavingsDepositScreen({ onBack, onConfirm, savingsBalance = 300000 }) {
  const { formatAmount } = useCurrency();
  const [amount, setAmount] = useState('');

  return (
    <div className="flex flex-col h-full bg-white animate-in fade-in duration-300">

      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-bold text-gray-900">Add to Savings</h1>
      </div>

      {/* Scrollable Content */}
      <div className="flex-1 overflow-y-auto px-6 pb-32">
        <div className="bg-gradient-to-br from-[#00875A] to-[#005F3F] p-8 rounded-[2.5rem] text-white mb-8 shadow-xl shadow-emerald-100">
          <div className="flex justify-between items-start mb-2">
            <p className="opacity-70 text-sm font-bold uppercase tracking-widest">
              Savings Vault
            </p>
            <Target className="opacity-50" />
          </div>
          <h2 className="text-4xl font-black">{formatAmount(savingsBalance)}</h2>
        </div>

        <div className="space-y-7">
          <label className="text-sm font-bold text-gray-700 ml-1">
            Amount to Save
          </label>
          <input
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder={formatAmount(0)}
            className="w-full p-5 rounded-3xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] text-2xl font-black text-center"
          />
          <p className="text-center text-xs text-gray-400 font-medium px-4">
            Funds will be moved from your main balance to your Nest Savings vault.
          </p>
        </div>

        {/* Fixed Action */}
        <div className="pb-64 bg-white border-t mt-6">
          <button
           onClick={() => onConfirm({ amount: Number(amount) })}
            className="w-full py-4 rounded-2xl font-bold text-white bg-[#00875A] shadow-lg shadow-emerald-100"
          >
            Confirm Save
          </button>
        </div>     
      </div>
    </div>
  );
}
